data.value:
select ( select count(membership_no) from sc_mem_m_membership_registered where sc_mem_m_membership_registered.member_status_code = '0' ) as count_mem
/*สมาชิกสามัญ (ราย)*/ ,( select count( distinct sc_mem_m_membership_registered.membership_no ) from sc_lon_m_loan_card ,sc_lon_m_contract ,sc_mem_m_membership_registered where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no and sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.member_status_code = '0' and sc_mem_m_membership_registered.mem_type = '01' and sc_lon_m_loan_card.loan_type not in ('สต','สก','สล','สร','สถ') /*ไม่รวม สหกรณ์อื่น ๆ*/ ) as count_mem_norm
,( select nvl(sum( sc_lon_m_loan_card.principal_balance ),0) from sc_lon_m_loan_card ,sc_lon_m_contract ,sc_mem_m_membership_registered where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no and sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.member_status_code = '0' and sc_mem_m_membership_registered.mem_type = '01' and sc_lon_m_loan_card.loan_type not in ('สต','สก','สล','สร','สถ') /*ไม่รวม สหกรณ์อื่น ๆ*/ ) as principal_balance_norm
/*สมาชิกสมทบ (ราย)*/ ,( select count( distinct sc_mem_m_membership_registered.membership_no ) from sc_lon_m_loan_card ,sc_lon_m_contract ,sc_mem_m_membership_registered where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no and sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.member_status_code = '0' and sc_mem_m_membership_registered.mem_type = '02' and sc_lon_m_loan_card.loan_type not in ('สต','สก','สล','สร','สถ') /*ไม่รวม สหกรณ์อื่น ๆ*/ ) as count_mem_ass
,( select nvl(sum( sc_lon_m_loan_card.principal_balance ),0) from sc_lon_m_loan_card ,sc_lon_m_contract ,sc_mem_m_membership_registered where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no and sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.member_status_code = '0' and sc_mem_m_membership_registered.mem_type = '02' and sc_lon_m_loan_card.loan_type not in ('สต','สก','สล','สร','สถ') /*ไม่รวม สหกรณ์อื่น ๆ*/ ) as principal_balance_ass
/*ยอดรวมลูกหนี้เงินให้กู้ยืมรายใหญ่ (บุคคล)*/ ,( SELECT sum(sc_lon_m_loan_card.principal_balance) as FROM sc_lon_m_loan_card, sc_mem_m_membership_registered, sc_mem_m_ucf_prename, sc_lon_m_rule, sc_lon_m_contract ,sc_acc_m_account_constant ,sc_mem_m_ucf_member_type ,( select sum(1)over(order by sum_principal_balance desc ) as seq_no /*เทียบเท่า comulative sum ถ้าเอา 50 คน ก้อเอา seq_no <= 50 */ ,membership_no ,sum_principal_balance from ( select sc_mem_m_membership_registered.membership_no ,sum(sc_lon_m_loan_card.principal_balance) as sum_principal_balance from sc_lon_m_loan_card ,sc_mem_m_membership_registered where sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no group by sc_mem_m_membership_registered.membership_no order by sum_principal_balance desc /*เรียงหนี้รวม จากมากไปหาน้อย*/ ) tab1 ) tab2
WHERE ( sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no ) and ( sc_mem_m_membership_registered.prename_code = sc_mem_m_ucf_prename.prename_code ) and ( sc_lon_m_loan_card.loan_type = sc_lon_m_rule.loan_type ) and ( sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no ) and ( ( sc_lon_m_loan_card.principal_balance > 0 ) ) and sc_mem_m_ucf_member_type.mem_type_code = sc_mem_m_membership_registered.mem_type and sc_lon_m_loan_card.membership_no = tab2.membership_no and tab2.seq_no <= 50 and sc_mem_m_membership_registered.mem_type < '03' ) as principal_balance_max_50
/*จำนวนบุคคลอื่นที่สหกรณ์ให้เงินกู้ยืมทั้งหมด (ราย)*/ ,( select count( distinct sc_mem_m_membership_registered.membership_no ) from sc_lon_m_loan_card ,sc_lon_m_contract ,sc_mem_m_membership_registered where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no and sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.member_status_code = '0' and sc_lon_m_loan_card.loan_type in ('สต','สก','สล','สร','สถ') /*สหกรณ์อื่น ๆ*/ ) as count_mem_coop
,( select nvl(sum( sc_lon_m_loan_card.principal_balance ),0) from sc_lon_m_loan_card ,sc_lon_m_contract ,sc_mem_m_membership_registered where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no and sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.member_status_code = '0' and sc_lon_m_loan_card.loan_type in ('สต','สก','สล','สร','สถ') /*สหกรณ์อื่น ๆ*/ ) as principal_balance_coop
from dual where 1 = 2
